+      // Tie off unused irq_id_ctrl bits
+      assign irq_id_ctrl[9:5] = 5'b00000;
+
+      // CLIC shv not used in basic mode
+      assign irq_clic_shv = 1'b0;
+      assign irq_clic_level = 8'h00;
     end
   endgenerate

